import { inject } from '@angular/core';
import {
  ActivatedRouteSnapshot,
  RedirectCommand,
  Routes,
  provideRouter,
  withComponentInputBinding
} from '@angular/router';
import { AuthStore } from './auth.store';
import { ProjectApi } from './project.api';

const authGuard = () =>
  inject(AuthStore).isLoggedIn()
    ? true
    : new RedirectCommand(['/login']);

const projectResolver = (route: ActivatedRouteSnapshot) =>
  inject(ProjectApi).getById(route.paramMap.get('id')!);

export const routes: Routes = [
  {
    path: 'projects/:id',
    loadComponent: () =>
      import('./project-page.component').then((m) => m.ProjectPageComponent),
    canActivate: [authGuard],
    resolve: { project: projectResolver }
  }
];

bootstrapApplication(AppComponent, {
  providers: [provideRouter(routes, withComponentInputBinding())]
});

import {
  HttpHandlerFn,
  HttpRequest,
  provideHttpClient,
  withInterceptors
} from '@angular/common/http';
import { inject } from '@angular/core';

export function authInterceptor(
  req: HttpRequest<unknown>,
  next: HttpHandlerFn
) {
  const token = inject(AuthStore).token();
  const authenticatedReq = req.clone({
    setHeaders: { Authorization: `Bearer ${token}` }
  });

  return next(authenticatedReq);
}

bootstrapApplication(AppComponent, {
  providers: [provideHttpClient(withInterceptors([authInterceptor]))]
});

